import subprocess, requests, json, datetime
from azure.identity import DefaultAzureCredential

def get_current_api_versions(bicep_dir: str) -> dict[str, str]:
    """Extract api-version values from all Bicep files in a directory."""
    import re, pathlib
    API_RE = re.compile(r"'([A-Za-z.]+/[A-Za-z]+)@(\d{4}-\d{2}-\d{2}(?:-preview)?)'")
    versions = {}
    for bicep in pathlib.Path(bicep_dir).rglob("*.bicep"):
        for m in API_RE.finditer(bicep.read_text()):
            resource_type = m.group(1)
            api_version = m.group(2)
            if resource_type not in versions or api_version > versions[resource_type]:
                versions[resource_type] = api_version
    return versions

def get_latest_api_versions(resource_types: list[str], subscription_id: str) -> dict[str, str]:
    """Return the latest stable API version for each resource type."""
    credential = DefaultAzureCredential()
    token = credential.get_token("https://management.azure.com/.default").token

    latest = {}
    providers = set(rt.split("/")[0] for rt in resource_types)

    for provider in providers:
        url = (
            f"https://management.azure.com/subscriptions/{subscription_id}"
            f"/providers/{provider}?api-version=2021-04-01"
        )
        resp = requests.get(url, headers={"Authorization": f"Bearer {token}"}, timeout=30)
        if not resp.ok:
            continue
        for rt_data in resp.json().get("resourceTypes", []):
            full_type = f"{provider}/{rt_data['resourceType']}"
            if full_type in resource_types:
                stable = [v for v in rt_data.get("apiVersions", []) if "preview" not in v]
                if stable:
                    latest[full_type] = stable[0]
    return latest

def api_version_gap_report(bicep_dir: str, subscription_id: str) -> list[dict]:
    current = get_current_api_versions(bicep_dir)
    latest = get_latest_api_versions(list(current.keys()), subscription_id)

    gaps = []
    for rtype, used in current.items():
        newest = latest.get(rtype)
        if newest and used < newest:
            gaps.append({
                "resource_type": rtype,
                "used_version": used,
                "latest_stable": newest,
                "months_behind": _months_between(used, newest),
            })
    return sorted(gaps, key=lambda g: -g["months_behind"])

def _months_between(v1: str, v2: str) -> int:
    d1 = datetime.date.fromisoformat(v1[:10])
    d2 = datetime.date.fromisoformat(v2[:10])
    return (d2.year - d1.year) * 12 + (d2.month - d1.month)

gaps = api_version_gap_report("./infra", "your-subscription-id")
print(f"API version gaps: {len(gaps)}")
for g in gaps[:10]:
    print(f"  {g['resource_type']}: {g['used_version']} → {g['latest_stable']} ({g['months_behind']} months behind)")
